export interface CareerRecommendation {
  role: string;
  explanation: string;
  matchScore: number;
  nextSkills: string[];
}

export interface CareerAnalysis {
  strategistOutlook: string;
  recommendations: CareerRecommendation[];
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface AnalysisResult {
  analysis: CareerAnalysis;
  sources: GroundingSource[];
}

export type LoadingStage = 'idle' | 'searching' | 'analyzing' | 'drafting';

import { GoogleGenAI } from "@google/genai";
import { AnalysisResult, CareerAnalysis, GroundingSource } from "../types";

export const performCareerAnalysis = async (profile: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `
    You are a high-level Career Strategist and Market Analyst. 
    Analyze the user's background and provide advice based on 2024-2025 job market trends.
    You MUST respond with a JSON object in the following structure, even though you are using search tools. 
    The JSON should be the ONLY content of your response text.

    Structure:
    {
      "strategistOutlook": "A friendly, professional summary of the user's positioning in the current market.",
      "recommendations": [
        {
          "role": "Role Name",
          "explanation": "Why this is a good fit based on current trends.",
          "matchScore": 85,
          "nextSkills": ["Skill A", "Skill B"]
        }
      ]
    }

    Ensure you search for actual hiring trends, high-growth sectors, and salary data for 2024 and 2025.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `User Profile: ${profile}`,
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    // Attempt to extract JSON from text (sometimes models wrap it in markdown)
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    const analysis: CareerAnalysis = jsonMatch 
      ? JSON.parse(jsonMatch[0]) 
      : { 
          strategistOutlook: "We encountered an issue parsing the detailed strategy, but here is a general overview...", 
          recommendations: [] 
        };

    // Extract grounding sources
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          sources.push({
            title: chunk.web.title || "Market Research Link",
            uri: chunk.web.uri
          });
        }
      });
    }

    // Filter unique sources
    const uniqueSources = Array.from(new Map(sources.map(s => [s.uri, s])).values());

    return {
      analysis,
      sources: uniqueSources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to analyze career data. Please check your network or try again.");
  }
};

import React, { useState, useEffect } from 'react';
import { LoadingStage } from '../types';

interface LoadingScreenProps {
  stage: LoadingStage;
}

const LoadingScreen: React.FC<LoadingScreenProps> = ({ stage }) => {
  const getProgress = () => {
    switch (stage) {
      case 'searching': return 'w-1/3';
      case 'analyzing': return 'w-2/3';
      case 'drafting': return 'w-full';
      default: return 'w-0';
    }
  };

  const getLabel = () => {
    switch (stage) {
      case 'searching': return 'Searching Job Market Trends 2024-2025...';
      case 'analyzing': return 'Analyzing Growth Sectors & Skill Gaps...';
      case 'drafting': return 'Drafting Personal Growth Strategy...';
      default: return '';
    }
  };

  return (
    <div className="flex flex-col items-center justify-center py-20 px-6 space-y-8 animate-fade-in-up">
      <div className="relative w-24 h-24">
        <div className="absolute inset-0 border-4 border-indigo-100 rounded-full"></div>
        <div className="absolute inset-0 border-4 border-indigo-600 rounded-full border-t-transparent animate-spin"></div>
      </div>

      <div className="text-center space-y-4 max-w-md">
        <h3 className="text-2xl font-black text-slate-900 tracking-tight">
          Consulting Intelligence
        </h3>
        <p className="text-slate-500 font-medium">
          {getLabel()}
        </p>

        <div className="w-full bg-slate-200 rounded-full h-1.5 overflow-hidden">
          <div 
            className={`h-full bg-indigo-600 transition-all duration-700 ease-in-out ${getProgress()}`}
          ></div>
        </div>
      </div>
    </div>
  );
};

export default LoadingScreen;

