import React, { useState } from 'react';
import { performCareerAnalysis } from './services/geminiService';
import { AnalysisResult, LoadingStage } from './types';
import LoadingScreen from './components/LoadingScreen';
import ResultsView from './components/ResultsView';

const App: React.FC = () => {
  const [profile, setProfile] = useState('');
  const [loadingStage, setLoadingStage] = useState<LoadingStage>('idle');
  const [results, setResults] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!profile.trim()) return;

    setError(null);
    setResults(null);

    // Multi-stage loading simulation
    setLoadingStage('searching');

    try {
      // Short delay to show searching stage
      await new Promise(r => setTimeout(r, 2000));
      setLoadingStage('analyzing');

      const analysisData = await performCareerAnalysis(profile);

      setLoadingStage('drafting');
      await new Promise(r => setTimeout(r, 1500));

      setResults(analysisData);
      setLoadingStage('idle');
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred.');
      setLoadingStage('idle');
    }
  };

  const handleReset = () => {
    setProfile('');
    setResults(null);
    setError(null);
    setLoadingStage('idle');
  };

  return (
    <div className="min-h-screen selection:bg-indigo-100 selection:text-indigo-900">
      {/* Header */}
      <header className="sticky top-0 z-50 glass-card border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-200 shadow-lg">
              <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <h1 className="text-xl font-black text-slate-900 tracking-tight italic">
              AI CAREER <span className="text-indigo-600">COACH</span>
            </h1>
          </div>
          <nav className="hidden md:flex space-x-8">
            <a href="#" className="text-sm font-bold text-slate-600 hover:text-indigo-600 transition-colors">Intelligence</a>
            <a href="#" className="text-sm font-bold text-slate-600 hover:text-indigo-600 transition-colors">Market Trends</a>
            <a href="#" className="text-sm font-bold text-slate-600 hover:text-indigo-600 transition-colors">Support</a>
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6 py-12 md:py-20">
        {loadingStage === 'idle' && !results && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-start animate-fade-in-up">
            {/* Left Content */}
            <div className="space-y-8">
              <div className="space-y-4">
                <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-600 text-xs font-black uppercase tracking-widest rounded-full">
                  2024-2025 Market Intelligence
                </span>
                <h2 className="text-5xl md:text-6xl font-black text-slate-900 tracking-tighter leading-[1.1]">
                  Scale your <span className="text-indigo-600">potential</span> with data.
                </h2>
                <p className="text-xl text-slate-500 font-medium leading-relaxed max-w-lg">
                  Input your professional blueprint. We'll cross-reference your skills with live job market shifts to architect your next career move.
                </p>
              </div>

              <div className="flex items-center space-x-4">
                <div className="flex -space-x-3 overflow-hidden">
                  {[1, 2, 3, 4].map(i => (
                    <img 
                      key={i} 
                      className="inline-block h-10 w-10 rounded-full ring-2 ring-white" 
                      src={`https://picsum.photos/100/100?random=${i}`} 
                      alt="User"
                    />
                  ))}
