                  Your Professional Blueprint
                </label>
                <textarea
                  required
                  value={profile}
                  onChange={(e) => setProfile(e.target.value)}
                  placeholder="Example: I'm a Senior Frontend Engineer with 6 years of experience in React and Node.js. I'm interested in AI engineering or transitioning into Product Management. My education is in Computer Science..."
                  className="w-full min-h-[250px] p-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-100 focus:border-indigo-500 outline-none transition-all resize-none text-slate-700 font-medium placeholder:text-slate-400"
                />
