                type="submit"
                disabled={!profile.trim()}
                className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white font-black py-5 rounded-2xl transition-all shadow-lg shadow-indigo-200 flex items-center justify-center space-x-2 text-lg uppercase tracking-wider"
