        {error && (
          <div className="max-w-md mx-auto p-6 bg-red-50 border border-red-100 rounded-2xl text-center space-y-4 animate-fade-in-up">
            <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto">
              <svg className="w-6 h-6 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-red-900 font-black">Analysis Failed</h3>
            <p className="text-red-700 text-sm font-medium">{error}</p>
            <button 
              onClick={handleReset}
              className="px-6 py-2 bg-red-600 text-white font-bold rounded-xl hover:bg-red-700 transition-colors"
            >
              Try Again
            </button>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="py-12 px-6 border-t border-slate-200 bg-white/50 mt-20">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center space-y-6 md:space-y-0">
          <p className="text-slate-400 text-sm font-medium">
            © 2025 AI Career Coach. Built for the modern workforce.
          </p>
          <div className="flex space-x-8">
            <a href="#" className="text-slate-400 hover:text-indigo-600 text-sm font-bold transition-colors">Privacy</a>
            <a href="#" className="text-slate-400 hover:text-indigo-600 text-sm font-bold transition-colors">Terms</a>
            <a href="#" className="text-slate-400 hover:text-indigo-600 text-sm font-bold transition-colors">API</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

