import { GoogleGenAI } from "@google/genai";
import { AnalysisResult, CareerAnalysis, GroundingSource, UserProfile } from "../types";

export const performCareerAnalysis = async (profile: UserProfile): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `
    You are a high-level Holistic Career Strategist. 
    Analyze the user's background (Degree, Skills, Experience) AND their personal passions (Hobbies, Interests).

    Your goal is to find career paths that leverage their professional expertise while aligning with their personal identity.
    Look for "Niche Synergies" (e.g., a Developer who loves Fitness might be perfect for Health-Tech or Wearables).

    You MUST respond with a JSON object in the following structure. 
    The JSON should be the ONLY content of your response text.

    Structure:
    {
      "strategistOutlook": "A professional summary of how their skills and hobbies create a unique value proposition in the 2024-2025 market.",
      "recommendations": [
        {
          "role": "Role Name",
          "explanation": "Professional fit analysis.",
          "personalSynergy": "Explain specifically how their hobbies/interests (e.g. ${profile.hobbies}) make them a unique or passionate candidate for this specific role.",
          "matchScore": 85,
          "nextSkills": ["Skill A", "Skill B"]
        }
      ]
    }

    Use Google Search to find specific industries or startups currently hiring or growing that match these cross-domain profiles.
  `;

  const userPrompt = `
    EDUCATION: ${profile.degree}
    SKILLS: ${profile.skills}
    EXPERIENCE: ${profile.experience}
    HOBBIES/INTERESTS: ${profile.hobbies}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: userPrompt,
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    const analysis: CareerAnalysis = jsonMatch 
      ? JSON.parse(jsonMatch[0]) 
      : { 
          strategistOutlook: "We encountered an issue parsing the detailed strategy, but here is a general overview...", 
          recommendations: [] 
        };

    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          sources.push({
            title: chunk.web.title || "Market Research Link",
            uri: chunk.web.uri
          });
        }
      });
    }

    const uniqueSources = Array.from(new Map(sources.map(s => [s.uri, s])).values());

    return {
      analysis,
      sources: uniqueSources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to analyze career data. Please check your network or try again.");
  }
};

